25.5 Marker Function
The marker function equivalent of trajMap() is addTrajPaths() which, much like addPolarMarkers(), allows you to customise your trajectory maps. For example, Figure 25.6 shows a way to plot multiple sets of trajectory data on one map (in this case, one arriving in London and the other in Paris).

library(leaflet)
library(openair)

france &lt;- importTraj("paris", year = 2009) |&gt;
  selectByDate(
    start = "15/4/2009",
    end = "21/4/2009"
  )

uk &lt;- importTraj(year = 2009) |&gt;
  selectByDate(
    start = "15/4/2009",
    end = "21/4/2009"
  )

leaflet() |&gt;
  addTiles() |&gt;
  addTrajPaths(
    data = uk,
    color = "blue",
    group = "London, UK",
    opacity = 0.25
  ) |&gt;
  addMarkers(
    data = dplyr::slice_head(uk, n = 1),
    lat = ~lat,
    lng = ~lon,
    group = "London, UK",
    label = "UK",
    layerId = "uk"
  ) |&gt;
  addTrajPaths(
    data = france,
    color = "red",
    group = "Paris, France",
    opacity = 0.25,
    layerId = "france"
  ) |&gt;
  addMarkers(
    data = dplyr::slice_head(france, n = 1),
    lat = ~lat,
    lng = ~lon,
    group = "Paris, France",
    label = "FR"
  ) |&gt;
  addLayersControl(overlayGroups = c("Paris, France", "London, UK"))






Figure 25.6: A demonstration of the use of addTrajPaths.
